    ed_srchAcctDeptCd.setValue("");
    ed_srchAcctDeptNm.setValue("");
    ed_srchFixedAsetNo.setValue("");
    cbx_lowerDeptIncluYn.setValue("");
    // ica_procDt.setValue("");
    //거래처사업자번호             000-00-00000000 101-28-66522
