scwin.sbm_addRetrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_master.setNoResultMessageVisible(true);
    let rowCnt = ds_master_temp.getRowCount();
    totalRows.setValue(ds_master.getRowCount()+rowCnt);

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
            if($c.gus.cfCheckCreateFlag()) {
                $c.gus.cfTurnCreateFlag(false);
            }else {
                // 조회결과가 존재하지 않습니다
                $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            }
        } else {
            let tempRow  = ds_master.getMatchedIndex("fixedAsetNo", ed_srchFixedAsetNo.getValue());
            let insertRow= 1;
            for(let i=0; i<rowCnt; i++) {
                insertRow = insertRow + Number(tempRow[0])+Number(i);
                let newRow = ds_master.insertRow(insertRow);
                ds_master.setRowJSON(newRow, ds_master_temp.getRowJSON(i), true);
            }
            ed_srchFixedAsetNo.setValue("");
        }
    }
};

scwin.sbm_addRetrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * 조회검증
 */
scwin.f_RetrieveValidate = async function() {
    /*if (ds_master.CountRow > 0 && ds_master.IsUpdated == true) {
    if (cfConfirmMsg(MSG_CM_CRM_005) == false)
    return;
    }*/
    let ret;
    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())
        && $c.gus.cfIsNull(acb_asetPatternCd.getValue())
        && $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) && $c.gus.cfIsNull(ed_srchAcctDeptNm.getValue())
        && $c.gus.cfIsNull(ed_srchFixedAsetNo.getValue())) {
        await $c.gus.cfAlertMsg("조회조건을 하나 이상 입력해 주세요.");
        ica_acqDtStDt.focus();
        return false;
    }

    ret = await $c.gus.cfValidate([tbl_search]);
    if (!ret) {
        return false;
    }

    //취득 일자 체크
    if ($c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && $c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ica_acqDtEndDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ica_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ica_acqDtEndDt.getValue())) {
        if (!await $c.gus.cfIsAfterDate(ica_acqDtStDt.getValue().trim(), ica_acqDtEndDt.getValue().trim())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ica_acqDtStDt.focus();
            return false;
        }
    }
    //매각일자 확인(TOBE 추가)
    ret = await $c.date.isDate(ica_procDt.getValue().substring(0, 8));
    if(!ret) {
        await $c.win.alert("올바른 마감년월을(를) 입력하십시오.");
        ica_closeYm.focus();
        return;
    }

    return true;
};


/**
 * 알괄반영처리 - 2012.01.30 추가
 * 관리자ID만 처리
 */
scwin.f_WholeProc = function() {
    let temp  = 0;
    let count = ds_master.getRowCount();
    for (let i=0; i<count; i++) {
        if (ds_master.getCellData(i, "procYn") == "1") {
            if( ds_master.getCellData(i, "asetPatternNm") == "토지" 
             || ds_master.getCellData(i, "asetPatternNm") == "건물" ) {
                ds_master.setCellData(i, "procArea", ds_master.getCellData(i, "area"   ) );     // 면적     -> 매각면적 		
                ds_master.setCellData(i, "procAmt" , ds_master.getCellData(i, "bookAmt") );     // 장부가액 -> 매각액 
            }else {
                ds_master.setCellData(i, "procQty" , ds_master.getCellData(i, "qty"    ) );     // 수량     -> 매각수량 
                ds_master.setCellData(i, "procAmt" , ds_master.getCellData(i, "bookAmt") );     // 장부가액 -> 매각액 				
            }
        } else {
            temp++
        }
    }
    if (temp == count) {
        $c.win.alert("선택된 행이 없습니다.");
        return;
    }
};


