            ed_clntNm.setValue(ds_clntNo.getCellData(0, "col2"));  // 거래처명
        }

    } else {
        ed_recverCrn.hidVal = "";         // 히든값
        ed_recverCrn.setValue("");        // 사업자번호
        ed_recverCrnNm.setValue("");      // 사업자명
